+fn clear_export_bundle_owned_outputs(output_dir: &Path) -> std::io::Result<()> {
+    for relative_path in BUNDLE_EXPORT_OWNED_DIRECTORIES {
+        remove_owned_output_path_if_exists(output_dir, relative_path)?;
